import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
import Grid from '@mui/material/Grid';

import movie from '../Assets/movie.png'
import workout from '../Assets/workout.png'
import commandLine from '../Assets/commandLine.png'

const BoxWithHover = styled(Box)`
  transition: .5s;
  &:hover {
    transform: scale(1.05); /* Enlarge the image on hover */
  }
`;

const projectItem = (image, name, func) => {
  return (
      <>
      {/* <Container> */}
      <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
        <Box component='img' src={image} sx={{height: '20vw', width: '20vw'}}/>
        <Typography> {name} </Typography>
      </Grid>
      {/* </Container> */}
      </>
);
}

function Projects () {
    const navigate = useNavigate();
    const reroute = (path) => {
        return () => navigate(path);
        // return () => window.open(path, '_blank');
    };

    return (
        <Container
        id='Projects'
        maxWidth='none'
        sx={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'space-evenly',
          mt: {xs: '15vh', sm: '25vh'}, 
          mb: '5vh',
          width: '75%',
        }}
        >
          <Typography 
            id='skills'
            variant='h2'
            my={4} 
          >
            Projects
          </Typography>

            {/* <Grid container direction='row' > */}
            <Grid container spacing={4} sx={{display: 'flex', flexDirection: 'row', alignItems: 'center'}} columns={{md: 3}}>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
                {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
                {projectItem(workout, 'Flat & Iron Abs', reroute('/FlatIronAbs') )}
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
                {projectItem(commandLine, 'OnlyKyles', reroute('/OnlyKyles') )}
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
                <Box component='img' src={movie} sx={{height: '20vw', width: '20vw'}}/>
                <Typography> 'Topher Emby' </Typography>
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
                <Box component='img' src={workout} sx={{height: '20vw', width: '20vw'}}/>
                <Typography> 'Flat & Iron Abs' </Typography>
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}} md={1}>
                <Box component='img' src={commandLine} sx={{height: '20vw', width: '20vw'}}/>
                <Typography> 'OnlyKyles' </Typography>
              </Grid>
            </Grid>

        </Container>
    );
}

export default Projects;
